public class ToListCollector<T> implements Collector<T, List<T>, List<T>> {
    @Override
    public Supplier<List<T>> supplier() {
        return ArrayList::new;
    }

    @Override
    public BiConsumer<List<T>, T> accumulator() {
        return List::add;
    }

    @Override
    public BinaryOperator<List<T>> combiner() {
        return (left, right) -> { left.addAll(right); return left; };
    }

    @Override
    public Function<List<T>, List<T>> finisher() {
        return Function.identity();
    }

    @Override
    public Set<Characteristics> characteristics() {
        return Set.of(Characteristics.IDENTITY_FINISH);
    }
}

public static <T, R> List<R> slidingWindow(
        List<T> items, int windowSize, Function<List<T>, R> aggregator) {
    List<R> results = new ArrayList<>();
    for (int i = 0; i <= items.size() - windowSize; i++) {
        List<T> window = items.subList(i, i + windowSize);
        results.add(aggregator.apply(window));
    }
    return results;
}
